type StringOrNumber = string | number;

function double(value: StringOrNumber): StringOrNumber {
  if (typeof value === "number") {
    return value * 2;
  }
  return value.repeat(2);
}

console.log(double(5));
console.log(double("ha"));

type Direction = "north" | "south" | "east" | "west";

function describe(dir: Direction): string {
  if (dir === "north" || dir === "south") return `${dir} (vertical)`;
  return `${dir} (horizontal)`;
}

console.log(describe("north"));
console.log(describe("east"));
console.log(describe("south"));

type Circle = { kind: "circle"; radius: number };
type Rectangle = { kind: "rectangle"; width: number; height: number };
type Shape = Circle | Rectangle;

function area(shape: Shape): number {
  switch (shape.kind) {
    case "circle":    return Math.PI * shape.radius ** 2;
    case "rectangle": return shape.width * shape.height;
  }
}

console.log(area({ kind: "circle", radius: 5 }).toFixed(2));
console.log(area({ kind: "rectangle", width: 4, height: 6 }));

type HasName = { name: string };
type HasAge = { age: number };
type Person = HasName & HasAge;

function introduce(p: Person): string {
  return `Hi, I'm ${p.name} and I'm ${p.age} years old.`;
}

console.log(introduce({ name: "Alice", age: 30 }));
console.log(introduce({ name: "Bob", age: 25 }));
